import { TabEventClient } from "../infra";
import { convertToValidClassName } from "../tool";


export const usePopupContainer = () => {
    const pathname = window.location.pathname || '';
    
    const getPopupContainer = () => {
        const key = TabEventClient.getKeyByPath(pathname);
        return (
            (document.querySelector(
                `.keep-alive-container-${convertToValidClassName(key ?? '')}`,
            ) as HTMLElement) || (document.body as HTMLElement)
        );
    };

    return {
        getPopupContainer,
    };
};
